import React, { useEffect } from 'react';
import Lenis from 'lenis';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

import Navbar from './components/Navbar.jsx';
import Hero from './components/Hero.jsx';
import Marquee from './components/Marquee.jsx';
import QuoteStatement from './components/QuoteStatement.jsx';
import ServicesSection from './components/ServicesSection.jsx';
import Story3D from './components/Story3D.jsx';
import MissionSection from './components/MissionSection.jsx';
import SolutionSection from './components/SolutionSection.jsx';
import ProductShowcase from './components/ProductShowcase.jsx';
import ConnorProjectsSection from './components/ConnorProjectsSection.jsx';
import TeamCarousel from './components/TeamCarousel.jsx';
import Footer from './components/Footer.jsx';
import CustomCursor from './components/CustomCursor.jsx';

gsap.registerPlugin(ScrollTrigger);

function App() {
  useEffect(() => {
    // Lenis smooth scroll configuration
    const lenis = new Lenis({
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)), 
      direction: 'vertical',
      gestureDirection: 'vertical',
      smooth: true,
      mouseMultiplier: 1,
      smoothTouch: false,
      touchMultiplier: 2,
      infinite: false,
    })

    // Sync Lenis with GSAP ScrollTrigger
    lenis.on('scroll', ScrollTrigger.update)

    gsap.ticker.add((time)=>{
      lenis.raf(time * 1000)
    })

    gsap.ticker.lagSmoothing(0)

    // Burn Transition Effect for Each Section
    const burnSections = gsap.utils.toArray('.burn-section');
    burnSections.forEach((section) => {
      gsap.fromTo(section,
        { 
          filter: 'brightness(3) contrast(1.2) sepia(0.8) hue-rotate(-20deg)',
          opacity: 0,
          scale: 0.95
        },
        {
          filter: 'brightness(1) contrast(1) sepia(0) hue-rotate(0deg)',
          opacity: 1,
          scale: 1,
          scrollTrigger: {
            trigger: section,
            start: 'top 90%',
            end: 'top 30%',
            scrub: 1,
          }
        }
      );
    });

    return () => {
      lenis.destroy()
      gsap.ticker.remove(lenis.raf)
    }
  }, []);

  return (
    <div className="antialiased text-white bg-black selection:bg-[#3FE56C] selection:text-black min-h-screen relative">
      <CustomCursor />

      {/* Global Film Grain Noise Overlay (Premium Print Touch) */}
      <div 
        className="pointer-events-none fixed inset-0 z-[100] h-full w-full opacity-[0.04]" 
        style={{ 
          backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")`, 
          backgroundRepeat: 'repeat' 
        }}
      />

      {/* Side-Pinned Vertical Achievement Badge */}
      <div className="fixed right-0 top-1/2 -translate-y-1/2 z-40 hidden lg:flex flex-col items-center bg-white text-black px-1.5 py-6 select-none shadow-[0_0_20px_rgba(0,0,0,0.5)] cursor-default transition-transform duration-300 hover:-translate-x-1">
        <span 
          className="font-['Space_Grotesk'] font-bold text-[10px] uppercase tracking-[0.3em] whitespace-nowrap" 
          style={{ writingMode: 'vertical-rl', transform: 'rotate(180deg)' }}
        >
          ISO 27001 <span className="text-[#3FE56C] my-3 inline-block">●</span> CERTIFIED
        </span>
      </div>

      <Navbar />
      <main className="relative z-10 w-full overflow-hidden">
        <div className="burn-section"><Hero /></div>
        <div className="burn-section"><Marquee /></div>
        <div className="burn-section"><QuoteStatement /></div>
        <div className="burn-section"><ServicesSection /></div>
        <div className="burn-section"><ProductShowcase /></div>
        <div className="burn-section"><Story3D /></div>
        <div className="burn-section"><MissionSection /></div>
        <div className="burn-section"><SolutionSection /></div>
        <div className="burn-section"><ConnorProjectsSection /></div>

        {/* Meet the Team 3D Carousel */}
        <div className="burn-section">
          <div className="bg-black py-24 border-t border-white/5 relative z-20">
            <div className="max-w-6xl mx-auto px-6 mb-16 text-center">
              <h2 className="text-4xl md:text-5xl font-semibold text-white tracking-tight">Meet the Minds</h2>
              <p className="text-xl text-[#86868b] mt-4 font-light">The visionaries behind Sentinel.</p>
            </div>
            <TeamCarousel />
          </div>
        </div>
        <div className="burn-section"><Footer /></div>
      </main>
    </div>
  );
}

export default App;

