import React, { useState, useEffect, useCallback } from 'react';
import './TeamCarousel.css';

const teamMembers = [
	{ name: "Alexander Vance", role: "Founder", img: "https://images.unsplash.com/photo-1560250097-0b93528c311a?w=800&auto=format&fit=crop&q=80" },
	{ name: "Elena Rostova", role: "Creative Director", img: "https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&auto=format&fit=crop&q=80" },
	{ name: "Marcus Chen", role: "Lead Developer", img: "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=800&auto=format&fit=crop&q=80" },
	{ name: "Sarah Jenkins", role: "UX Designer", img: "https://images.unsplash.com/photo-1580489944761-15a19d654956?w=800&auto=format&fit=crop&q=80" },
	{ name: "David Thorne", role: "Marketing Manager", img: "https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?w=800&auto=format&fit=crop&q=80" },
	{ name: "Maya Patel", role: "Product Manager", img: "https://images.unsplash.com/photo-1598550874175-4d0ef43eceb1?w=800&auto=format&fit=crop&q=80" }
];

const ChevronUp = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="18 15 12 9 6 15"></polyline>
  </svg>
);

const ChevronDown = () => (
  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="6 9 12 15 18 9"></polyline>
  </svg>
);

const TeamCarousel = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);
  const [touchStart, setTouchStart] = useState(0);

  const updateCarousel = useCallback((newIndex) => {
    if (isAnimating) return;
    setIsAnimating(true);
    setCurrentIndex((newIndex + teamMembers.length) % teamMembers.length);
    setTimeout(() => setIsAnimating(false), 800);
  }, [isAnimating]);

  const handleKeyDown = useCallback((e) => {
    if (e.key === "ArrowUp") {
      updateCarousel(currentIndex - 1);
    } else if (e.key === "ArrowDown") {
      updateCarousel(currentIndex + 1);
    }
  }, [currentIndex, updateCarousel]);

  useEffect(() => {
    document.addEventListener("keydown", handleKeyDown);
    return () => document.removeEventListener("keydown", handleKeyDown);
  }, [handleKeyDown]);

  const handleTouchStart = (e) => setTouchStart(e.targetTouches[0].clientY);
  const handleTouchEnd = (e) => {
    const touchEnd = e.changedTouches[0].clientY;
    const diff = touchStart - touchEnd;
    if (Math.abs(diff) > 50) {
      if (diff > 0) updateCarousel(currentIndex + 1);
      else updateCarousel(currentIndex - 1);
    }
  };

  const getCardClass = (index) => {
    const offset = (index - currentIndex + teamMembers.length) % teamMembers.length;
    if (offset === 0) return "center";
    if (offset === 1) return "down-1";
    if (offset === 2) return "down-2";
    if (offset === teamMembers.length - 1) return "up-1";
    if (offset === teamMembers.length - 2) return "up-2";
    return "hidden";
  };

  return (
    <div className="tc-container pointer-events-auto" onTouchStart={handleTouchStart} onTouchEnd={handleTouchEnd}>
      <div className="tc-main-container">

        <div className="tc-carousel-section">
          <div className="tc-carousel-container">
            <button className="tc-nav-arrow up md:hidden absolute top-[-60px]" onClick={() => updateCarousel(currentIndex - 1)}>
               <ChevronUp />
            </button>

            <div className="tc-carousel-track">
              {teamMembers.map((member, i) => (
                <div key={i} className={`tc-card ${getCardClass(i)}`} onClick={() => updateCarousel(i)}>
                  <img src={member.img} alt={member.name} />
                </div>
              ))}
            </div>

            <button className="tc-nav-arrow down md:hidden absolute bottom-[-60px]" onClick={() => updateCarousel(currentIndex + 1)}>
               <ChevronDown />
            </button>
          </div>
        </div>

        <div className="tc-controls-section">
          <div className="flex flex-row gap-8 items-center justify-center hidden md:flex">
            <button className="tc-nav-arrow up" onClick={() => updateCarousel(currentIndex - 1)}>
              <ChevronUp />
            </button>
            <button className="tc-nav-arrow down" onClick={() => updateCarousel(currentIndex + 1)}>
              <ChevronDown />
            </button>
          </div>

          <div className="tc-member-info">
            <h2 className="tc-member-name transition-opacity duration-300">{teamMembers[currentIndex].name}</h2>
            <p className="tc-member-role transition-opacity duration-300">{teamMembers[currentIndex].role}</p>
          </div>

          <div className="tc-dots">
            {teamMembers.map((_, i) => (
              <div 
                key={i} 
                className={`tc-dot ${i === currentIndex ? 'active' : ''}`}
                onClick={() => updateCarousel(i)}
              />
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

export default TeamCarousel;

