import React, { useRef, useEffect } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

const PROJECTS = [
  {
    id: '01',
    year: '2026',
    title: 'Modern Telecom',
    desc: 'Connecting the world with high-speed, reliable infrastructure.',
    image: '/brandin-ai-bg.webp', // reusing existing asset
    bgColor: '#111111'
  },
  {
    id: '02',
    year: '2025',
    title: 'Sentinel AI',
    desc: 'Advanced neural safety networks for industrial protection.',
    image: '/sentinel-helmet.png',
    bgColor: '#1a1a1a'
  },
  {
    id: '03',
    year: '2026',
    title: 'Lyceum',
    desc: 'The next generation learning and management platform.',
    image: '/sentinel-wearable.png',
    bgColor: '#0a0a0a'
  }
];

const ConnorProjectsSection = () => {
  const containerRef = useRef(null);

  useEffect(() => {
    // Wrap in gsap.context for safe cleanup in React
    const ctx = gsap.context(() => {
      // Connor Love style sticky stacked cards animation
      const cards = gsap.utils.toArray('.connor-card');

      cards.forEach((card, i) => {
        // We don't animate the last card scaling down
        if (i === cards.length - 1) return;

        gsap.to(card, {
          scale: 0.9 + (i * 0.02), // subtle scale down to create depth
          opacity: 0.5,
          filter: 'blur(4px)',
          scrollTrigger: {
            trigger: card,
            start: 'top top',
            end: 'bottom top',
            scrub: true,
            pin: true,
            pinSpacing: false, // Allows the next card to overlap
          }
        });
      });

      // appearByWords animation (Connor Love style text reveal)
      const titles = gsap.utils.toArray('.appear-by-words');
      titles.forEach((title) => {
        gsap.fromTo(title, 
          { y: 50, opacity: 0, rotateX: -45 },
          { 
            y: 0, opacity: 1, rotateX: 0, 
            duration: 1.2, 
            ease: 'expo.out',
            scrollTrigger: {
              trigger: title,
              start: 'top 85%',
            }
          }
        );
      });
    }, containerRef);

    return () => ctx.revert();
  }, []);

  return (
    <section ref={containerRef} className="relative w-full bg-black text-white pt-32 pb-32">
      <div className="max-w-6xl mx-auto px-6 md:px-12 mb-24">
        <h1 className="appear-by-words font-['Space_Grotesk'] text-5xl md:text-7xl font-bold uppercase tracking-tight mb-6">
          Selected Projects
