        <div className="w-16 h-[2px] bg-[#3FE56C] mb-8" />
      </div>

      <div className="relative w-full">
        {PROJECTS.map((project, index) => (
          <div 
            key={project.id} 
            className="connor-card h-screen w-full sticky top-0 flex items-center justify-center p-6 md:p-12 overflow-hidden"
            style={{ zIndex: index + 10 }}
          >
            <div 
              className="relative w-full max-w-6xl h-[80vh] md:h-[85vh] rounded-3xl overflow-hidden flex flex-col justify-end p-8 md:p-16 border border-white/10"
              style={{ backgroundColor: project.bgColor, boxShadow: '0 -20px 60px rgba(0,0,0,0.5)' }}
            >
              {/* Background Image / Canvas Simulation */}
              <div className="absolute inset-0 z-0 opacity-40 mix-blend-luminosity">
                <img src={project.image} alt={project.title} className="w-full h-full object-cover object-center" />
                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/50 to-transparent" />
              </div>

              <div className="relative z-10 flex flex-col md:flex-row md:items-end justify-between gap-8">
                <div>
                  <h6 className="text-[#3FE56C] font-['Inter'] text-sm tracking-[0.3em] uppercase mb-4">
