import React, { useEffect, useRef } from 'react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import Content from './content.jsx';
import { useNavigate } from 'react-router-dom';

gsap.registerPlugin(ScrollTrigger);

const numLines = 9;
const fontSizeBase = 6;
const angle = 360 / numLines;

const TubeScroll = () => {
  const navigate = useNavigate();
  const stageRef = useRef(null);

  useEffect(() => {
    let radius = 0;
    let origin = '50% 50% 0px';

    const set3D = () => {
      const width = window.innerWidth;
      const fontSizePx = (width / 100) * fontSizeBase;
      radius = (fontSizePx / 2) / Math.sin((180 / numLines) * (Math.PI / 180));
      origin = `50% 50% -${radius}px`;
    };

    const setProps = (targets) => {
      targets.forEach((target) => {
        const paramSet = gsap.quickSetter(target, 'css');
        const degrees = gsap.getProperty(target, 'rotateX');
        const radians = degrees * (Math.PI / 180);
        const conversion = Math.abs(Math.cos(radians) / 2 + 0.5);
        paramSet({
          opacity: conversion + 0.5,
          fontWeight: 200 + 700 * conversion,
          fontStretch: `${100 + 700 * conversion}%`,
        });
      });
    };

    const positionTxt = () => {
      gsap.set('.tube-line', {
        rotationX: (i) => -angle * i,
        z: radius,
        transformOrigin: origin,
      });
    };

    set3D();
    positionTxt();
    setProps(gsap.utils.toArray('.tube-line'));

    // Make visible
    gsap.set(stageRef.current, { autoAlpha: 1 });

    const master = gsap.timeline({
      scrollTrigger: {
        trigger: stageRef.current,
        scrub: 2,   // higher = smoother / more lag behind scroll
        start: 'top top',
        end: 'bottom bottom',
      },
    });

    master.to('.tube-line', {
      rotateX: '+=1080',
      ease: 'none',
      onUpdate() {
        setProps(this.targets());
      },
    }, 0);

    master.to('.tube-el', {
      perspective: '2vw',
      ease: 'expo.out',
    }, 0);

    const handleResize = () => {
      set3D();
      positionTxt();
      ScrollTrigger.refresh();
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      master.kill();
      ScrollTrigger.getAll().forEach((t) => t.kill());
    };
  }, []);

  return (
    <div className="bg-black text-white">
      <style>{`
        :root { --fontSize: ${fontSizeBase}; }
        .tube-stage {
          height: 600vh;
          width: 100%;
          visibility: hidden;
          position: relative;
        }
        .tube-container {
          position: sticky;
          top: 0;
          width: 100%;
          height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          pointer-events: none;
          overflow: hidden;
        }
        .tube-el { perspective: 100vw; }
        .tube__inner {
          position: relative;
          transform-style: preserve-3d;
        }
        .tube-line {
          position: absolute;
          top: 50%; left: 50%;
          transform: translate(-50%, -50%);
          white-space: nowrap;
          font-family: 'Inter', system-ui, sans-serif;
          font-size: calc(var(--fontSize) * 1vw);
          text-transform: uppercase;
          line-height: 1;
          transform-style: preserve-3d;
          font-weight: 800;
        }
        @media (max-width: 640px) {
          .tube-el { perspective: 60vw; }
          .tube-line { font-size: calc(var(--fontSize) * 1.3vw); }
        }
      `}</style>

      <div ref={stageRef} className="tube-stage">
        <div className="tube-container">
          <div className="tube-el">
            <div className="tube__inner">
              {[...Array(numLines)].map((_, i) => (
                <h1 key={i} className="tube-line">
                  <span className="text-gray-500">SPY HELMET</span>
                </h1>
              ))}
            </div>
          </div>
        </div>
        <div>
          {[...Array(5)].map((_, i) => <Content key={i} />)}
        </div>
      </div>

      <div
        onClick={() => navigate('/Solution')}
        className="fixed bottom-8 left-8 text-[10px] uppercase tracking-widest opacity-45 cursor-pointer z-50"
        style={{ pointerEvents: 'auto' }}
      >
        <p className="mt-4 text-lg">
          <span className="text-[#86e8d6] font-bold">SMART</span>
          <span> SOLUTION</span>
        </p>
      </div>
    </div>
  );
};

export default TubeScroll;

