import React, { useRef, useEffect, useState } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Environment, Float } from '@react-three/drei';
import * as THREE from 'three';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);
import BrandLogo3D from './BrandLogo3D';

// ─────────────────────────────────────────────────────────────────────────────
// MOUSE TRACKING
// ─────────────────────────────────────────────────────────────────────────────
function useMouse() {
  const mouse = useRef({ x: 0, y: 0 });
  useEffect(() => {
    const move = (e) => {
      mouse.current.x = (e.clientX / window.innerWidth - 0.5) * 2;
      mouse.current.y = (e.clientY / window.innerHeight - 0.5) * 2;
    };
    window.addEventListener('mousemove', move, { passive: true });
    return () => window.removeEventListener('mousemove', move);
  }, []);
  return mouse;
}

// ─────────────────────────────────────────────────────────────────────────────
// SCROLL PROGRESS SHARED REF  (updated by ScrollTrigger, read by useFrame)
// ─────────────────────────────────────────────────────────────────────────────
const scrollProgress = { value: 0 }; // module-level, 0-1

// ─────────────────────────────────────────────────────────────────────────────
// 3-D LOGO — entirely driven by scrollProgress + mouse in useFrame
// ─────────────────────────────────────────────────────────────────────────────
function LogoModel({ modelRef }) {
  const innerRef = useRef();
  const mouse = useMouse();
  const lerpedMX = useRef(0);
  const lerpedMY = useRef(0);

  useFrame(({ clock }) => {
    if (!innerRef.current || !modelRef.current) return;
    const t = clock.getElapsedTime();
    const p = scrollProgress.value; // 0 → 1

    // ── Smooth mouse parallax
    lerpedMX.current += (mouse.current.x * 0.15 - lerpedMX.current) * 0.06;
    lerpedMY.current += (mouse.current.y * 0.12 - lerpedMY.current) * 0.06;

    // ── Scale: 0.65 → 1.4 → 1.1 (rises then settles)
    const scaleVal = p < 0.6
      ? 0.65 + p * 1.25                     // grow
      : 1.4 - (p - 0.6) * 0.75;             // shrink slightly at end
    const s = Math.max(0.3, scaleVal);
    modelRef.current.scale.set(s, s, s);

    // ── Position X: gentle side drift — never off-screen
    // 0→0.33: centre, 0.33→0.66: nudge right, 0.66→1: back centre
    let posX = 0;
    if (p < 0.33) posX = 0;
    else if (p < 0.66) posX = ((p - 0.33) / 0.33) * 0.6;
    else posX = 0.6 * (1 - (p - 0.66) / 0.34);
    modelRef.current.position.x = posX + lerpedMX.current * 0.3;

    // ── Position Y: gentle float up
    modelRef.current.position.y = Math.sin(t * 0.5) * 0.12 + p * 0.4 + lerpedMY.current * 0.2;

    // ── Rotation Y: ONE full spin total over the entire scroll
    modelRef.current.rotation.y = p * Math.PI * 2 + lerpedMX.current * 0.3;

    // ── Rotation X: slight tilt back in middle, straight at start/end
    const tiltX = Math.sin(p * Math.PI) * 0.2;
    modelRef.current.rotation.x = tiltX + lerpedMY.current * 0.15;

    // ── Z roll: subtle oscillation
    modelRef.current.rotation.z = Math.sin(p * Math.PI * 2) * 0.06 + lerpedMX.current * 0.05;

    // ── Inner idle breathe
    innerRef.current.rotation.y = Math.sin(t * 0.4) * 0.08;
  });

  return (
    <group ref={modelRef} position={[0, 0, 0]}>
      <Float floatIntensity={0.4} speed={1.5} rotationIntensity={0.04}>
        <BrandLogo3D ref={innerRef} position={[0, -0.8, 0]} scale={0.65} />
      </Float>
    </group>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// DYNAMIC LIGHTS
// ─────────────────────────────────────────────────────────────────────────────
function DynamicLights({ phase }) {
  const configs = [
    { c1: '#B0C6FF', c2: '#3FE56C' },
    { c1: '#3FE56C', c2: '#00ffcc' },
    { c1: '#ffb347', c2: '#3FE56C' },
    { c1: '#3FE56C', c2: '#ffffff' },
  ];
  const cfg = configs[Math.min(phase, 3)];
  return (
    <>
      <ambientLight intensity={0.55} />
      <directionalLight position={[5, 8, 5]} intensity={1.4} castShadow color="#ffffff" />
      <pointLight position={[-5, 3, 2]} intensity={2.0} color={cfg.c1} />
      <pointLight position={[5, 3, 2]}  intensity={2.0} color={cfg.c2} />
      <pointLight position={[0, -4, 4]} intensity={0.9} color="#00C853" />
    </>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// PANEL DATA
// ─────────────────────────────────────────────────────────────────────────────
const PANELS = [
  {
    id: 'genesis', side: 'left', label: 'OUR STORY', num: '01',
    title: ['THE', 'GENESIS'],
    body: 'Forged in the void of uncertainty. We built a sentinel that sees the unseen, anticipating danger before it arrives.',
    hint: '↓ Scroll to explore',
  },
