// ─────────────────────────────────────────────────────────────────────────────
// STORY PANEL — ScrollTrigger per panel
// ─────────────────────────────────────────────────────────────────────────────
function StoryPanel({ panel }) {
  const ref = useRef(null);
  const isRight = panel.side === 'right';
  const isCenter = panel.side === 'center';

  useEffect(() => {
    if (!ref.current) return;
    const els = ref.current.querySelectorAll('.anim-el');
    const fromX = isCenter ? 0 : isRight ? 40 : -40;

    gsap.set(els, { opacity: 0, y: 30, x: fromX });

    const ctx = gsap.context(() => {
      ScrollTrigger.create({
        trigger: ref.current,
        start: 'top 70%',
        end: 'bottom 25%',
        onEnter: () => gsap.to(els, { opacity: 1, y: 0, x: 0, stagger: 0.1, duration: 0.75, ease: 'power3.out' }),
        onLeave: () => gsap.to(els, { opacity: 0, y: -25, stagger: 0.05, duration: 0.45, ease: 'power2.in' }),
        onEnterBack: () => gsap.to(els, { opacity: 1, y: 0, x: 0, stagger: 0.08, duration: 0.6, ease: 'power3.out' }),
        onLeaveBack: () => gsap.to(els, { opacity: 0, y: 30, stagger: 0.05, duration: 0.45, ease: 'power2.in' }),
      });
    }, ref);

    return () => ctx.revert();
  }, []);

  if (isCenter) {
    return (
      <div ref={ref} className="h-screen flex items-center justify-center px-8">
        <div className="text-center max-w-2xl pointer-events-auto">
