            <span className="text-[#3FE56C]">{panel.title[1]}</span>
          </h2>
          <p className="anim-el text-white/40 font-['Manrope'] font-light mb-10 max-w-md mx-auto leading-relaxed text-sm">
            {panel.body}
          </p>
          <div className="anim-el w-full h-[1px] bg-white/[0.08] mb-10" />
          <div className="anim-el flex items-center justify-center gap-4">
            <a href="#contact"
              className="px-8 py-4 rounded-full border border-white/15 text-sm uppercase tracking-[0.25em] text-white/60 hover:text-white hover:border-white/40 transition-all duration-300 font-['Inter']">
