        )}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// PROGRESS HUD
// ─────────────────────────────────────────────────────────────────────────────
function ProgressHUD({ phase }) {
  return (
    <div className="fixed right-5 top-1/2 -translate-y-1/2 z-50 flex flex-col gap-2.5 pointer-events-none">
      {PANELS.map((p, i) => (
        <div key={p.id} className="transition-all duration-500"
          style={{
            width: phase === i ? '22px' : '5px',
            height: '5px',
            borderRadius: '3px',
            background: phase === i ? '#3FE56C' : 'rgba(255,255,255,0.12)',
          }}
        />
      ))}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN SECTION
// ─────────────────────────────────────────────────────────────────────────────
const Story3D = () => {
  const containerRef = useRef(null);
  const modelRef = useRef(null);
  const [phase, setPhase] = useState(0);

  useEffect(() => {
    const timer = setTimeout(() => {
      // Single unified ScrollTrigger that writes to the shared module ref
      ScrollTrigger.create({
        trigger: containerRef.current,
        start: 'top top',
        end: 'bottom bottom',
        scrub: 1.5,
        onUpdate: (self) => {
          scrollProgress.value = self.progress;
          // Phase detection for lights & HUD
          const p = self.progress;
          if (p < 0.25)      setPhase(0);
          else if (p < 0.5)  setPhase(1);
          else if (p < 0.75) setPhase(2);
          else               setPhase(3);
        },
      });
    }, 300);

    return () => {
      clearTimeout(timer);
      ScrollTrigger.getAll().forEach(t => t.kill());
      scrollProgress.value = 0;
    };
  }, []);

  return (
    <section
      ref={containerRef}
      className="w-full relative h-[400vh] bg-[#080808]"
      style={{ borderTop: '1px solid rgba(255,255,255,0.05)' }}
    >
      <ProgressHUD phase={phase} />

      {/* Ghost section number */}
      <div className="absolute top-12 right-4 font-['Bebas_Neue'] text-white/[0.018] select-none leading-none pointer-events-none z-[5]"
        style={{ fontSize: '18rem' }}>
        03
      </div>

      {/* ── STICKY 3D CANVAS ── */}
      <div className="sticky top-0 left-0 w-full h-screen overflow-hidden">
        <div className="absolute top-0 left-0 right-0 h-[1px] bg-white/5 z-20" />

        <div className="absolute inset-0 z-0">
          <Canvas
            shadows
            camera={{ position: [0, 0.2, 6.5], fov: 48 }}
            gl={{ antialias: true, alpha: false }}
            style={{ background: '#080808' }}
          >
            <DynamicLights phase={phase} />
            <Environment preset="studio" />
            <LogoModel modelRef={modelRef} />
          </Canvas>
        </div>

        {/* Vignette */}
        <div className="absolute inset-0 pointer-events-none z-10"
          style={{ background: 'radial-gradient(ellipse at center, transparent 40%, rgba(8,8,8,0.7) 100%)' }} />

        {/* Phase strip */}
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-20 flex items-center gap-2">
          {PANELS.map((p, i) => (
            <div key={p.id} className="transition-all duration-700 rounded-full"
              style={{
                height: '2px',
                width: phase === i ? '36px' : '14px',
                background: phase === i ? '#3FE56C' : 'rgba(255,255,255,0.1)',
              }}
            />
          ))}
        </div>
      </div>

      {/* ── COPY PANELS ── */}
      <div className="absolute top-0 w-full z-10 pointer-events-none">
        {PANELS.map((panel) => (
          <StoryPanel key={panel.id} panel={panel} />
        ))}
      </div>
    </section>
  );
};

export default Story3D;

