import React, { useRef } from 'react';
import gsap from 'gsap';
import { useGSAP } from '@gsap/react';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

gsap.registerPlugin(ScrollTrigger);

// ─── HERO SECTION ────────────────────────────────────────────────────
const Hero = () => {
  const robotRef = useRef(null);
  const glowRef = useRef(null);
  const scanRef = useRef(null);

  useGSAP(() => {

    /* ── 1. Text reveal ── */
    gsap.fromTo('.reveal-text',
      { y: 50, opacity: 0 },
      { y: 0, opacity: 1, duration: 1.5, stagger: 0.15, ease: 'power4.out', delay: 0.2 }
    );

    /* ── 2. Robot: slow cinematic zoom-in + subtle drift (Ken Burns) ── */
    gsap.fromTo(robotRef.current,
      { scale: 1.12, x: 30, opacity: 0 },
      {
        scale: 1.22,      // drifts into a slight zoom
        x: -20,          // slow horizontal pan left
        opacity: 0.88,
        duration: 18,
        ease: 'none',
        repeat: -1,
        yoyo: true,       // reverses back smoothly
      }
    );

    /* ── 3. Vertical breathing (up-down bob) ── */
    gsap.fromTo(robotRef.current,
      { y: 0 },
      {
        y: -28,
        duration: 6,
        ease: 'sine.inOut',
        repeat: -1,
        yoyo: true,
      }
    );

    /* ── 4. Ambient glow pulse ── */
    gsap.to(glowRef.current, {
      opacity: 0.55,
      scale: 1.15,
      duration: 3,
      ease: 'sine.inOut',
      repeat: -1,
      yoyo: true,
    });

    /* ── 5. Scan-line sweep ── */
    gsap.fromTo(scanRef.current,
      { y: '-100%', opacity: 0.6 },
      {
        y: '110%',
        opacity: 0,
        duration: 3.5,
        ease: 'none',
        repeat: -1,
        repeatDelay: 4,
      }
    );

    /* ── 6. Parallax on scroll – robot drifts up as user scrolls ── */
    gsap.to(robotRef.current, {
      y: '-=120',
      ease: 'none',
      scrollTrigger: {
        trigger: '.hero-section',
        start: 'top top',
        end: 'bottom top',
        scrub: 1.5,
      }
    });

  });

  return (
    <section className='hero-section bg-black text-[#111] h-screen relative overflow-hidden flex flex-col font-["Inter",sans-serif]'>

      {/* ── BACKGROUND: ROBOT with motion ── */}
      <div className="absolute inset-0 z-0 bg-[#E83F00] overflow-hidden">

        {/* Robot image — animated via GSAP refs */}
        <div
          ref={robotRef}
          className="absolute inset-[-10%] bg-no-repeat mix-blend-luminosity will-change-transform"
          style={{
            backgroundImage: "url('/brandin-ai-bg.webp')",
            backgroundSize: 'cover',
            backgroundPosition: 'center center',
            transformOrigin: 'center center',
          }}
        />

        {/* Warm orange colour wash */}
        <div className="absolute inset-0 bg-[#E83F00]/35 mix-blend-multiply" />

        {/* Animated scan-line sweep */}
        <div
          ref={scanRef}
          className="absolute left-0 right-0 h-[3px] pointer-events-none"
          style={{
            background: 'linear-gradient(90deg, transparent 0%, rgba(232,63,0,0.8) 40%, rgba(255,140,60,1) 50%, rgba(232,63,0,0.8) 60%, transparent 100%)',
            filter: 'blur(1px)',
            mixBlendMode: 'screen',
            top: 0,
          }}
        />

        {/* Pulsing glow blob behind the robot */}
        <div
          ref={glowRef}
          className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 rounded-full pointer-events-none will-change-transform"
          style={{
            width: '600px',
            height: '600px',
            background: 'radial-gradient(circle, rgba(255,100,0,0.25) 0%, transparent 70%)',
            mixBlendMode: 'screen',
          }}
