    title: 'NEURAL LINK', 
    desc: 'Biometric sensors monitor operator stress and vitals in real-time.', 
    icon: '01',
    color: '#3FE56C'
  },
  { 
    title: 'HAZARD PREDICTION', 
    desc: 'Core AI identifies environmental anomalies before they escalate.', 
    icon: '02',
    color: '#3FE56C'
  },
