            trigger: '.feature-box',
            start: 'top 80%',
            end: 'top 30%',
            scrub: 1,
          }
        }
      );

      // Main header animation
      gsap.fromTo('.solution-header', 
        { opacity: 0, scale: 0.95 }, 
        { 
          opacity: 1, scale: 1,
