         {/* Hexagonal grid pattern - using SVG pattern */}
         <svg width="100%" height="100%" className="opacity-[0.03]">
            <pattern id="hex" width="50" height="43.3" patternUnits="userSpaceOnUse" viewBox="0 0 50 43.3">
                <path d="M25 0L50 14.4V43.3L25 28.9L0 43.3V14.4L25 0z" fill="none" stroke="#3FE56C" strokeWidth="1" />
            </pattern>
            <rect width="100%" height="100%" fill="url(#hex)" />
         </svg>
      </div>

      <div className="relative z-10 max-w-7xl mx-auto flex flex-col md:flex-row gap-20 items-center">
        <div className="flex-1 solution-header">
           <span className="text-[#3FE56C] font-['Inter'] uppercase tracking-[0.5em] text-xs mb-4 block">Section 02 // The Solution</span>
           <h2 className="text-6xl md:text-9xl font-['Space_Grotesk'] font-bold leading-none uppercase tracking-tighter mb-8">
             SENTINEL<br /><span className="text-[#3FE56C]">X-01</span>
           </h2>
           <p className="text-xl font-['Manrope'] text-gray-300 max-w-xl font-light leading-relaxed mb-12">
             The world's first cinematic safety intelligence platform. Forged from aerospace-grade titanium and powered by the Sentinel neural processor.
           </p>

           <button className="group relative px-10 py-5 bg-[#3FE56C] text-[#131313] font-['Space_Grotesk'] font-bold uppercase tracking-widest rounded-full overflow-hidden transition-all duration-300 hover:scale-105 active:scale-95">
              <span className="relative z-10">Pre-Order Now</span>
              <div className="absolute inset-0 bg-white opacity-0 group-hover:opacity-20 transition-opacity duration-300"></div>
           </button>
        </div>

        <div className="flex-1 w-full space-y-8">
           {Features.map((f, i) => (
             <div key={i} className="feature-box p-10 bg-black/40 backdrop-blur-3xl border border-white/5 rounded-3xl group hover:border-[#3FE56C]/20 transition-all duration-500 relative overflow-hidden">
                <div className="absolute top-4 right-8 font-['Space_Grotesk'] text-4xl font-black text-white/5 italic group-hover:text-[#3FE56C]/10 transition-colors duration-500">
